+import { ViewItem } from '../data/ViewItem';
+import { REUSE_VIEW_TYPE_ITEM, nodePoolItem, flowItemWrapper } from '../utils/NodePoolManager';
+import { NodeContainerProxy } from './NodeContainerProxy';
+
+@Reusable
+@Component
+export struct ReusableFlowItem {
+  @State item: ViewItem | undefined = undefined;
+
+  aboutToReuse(params: Record<string, ESObject>): void {
+    this.item = params.item as ViewItem;
+  }
+
+  aboutToRecycle(): void {
+    this.item = undefined;
+  }
+
+  build() {
+    FlowItem() {
+      if (this.item !== undefined) {
+        NodeContainerProxy({
+          nodeItem: nodePoolItem.getNode(REUSE_VIEW_TYPE_ITEM, {
+            item: this.item
+          }, flowItemWrapper)
+        })
+      }
+    }
+    .width($r('app.string.nodepool_percent_100'))
+    .backgroundColor(Color.White)
+    .clip(true)
+    .borderRadius($r('app.float.common_border_radius_7'))
+  }
+}

